			BeadID:    beadID,
			AttemptID: attemptID,
			WorkerID:  runtime.WorkerID,
			BaseRev:   baseRev,
			ResultRev: baseRev, // no commits; ResultRev == BaseRev signals no output
			ExitCode:  1,
			Error:     err.Error(),
			Outcome:   ExecuteBeadOutcomeTaskFailed,
