	}
	if err := WriteExecutionCleanupMetadata(wtPath, ExecutionCleanupMetadata{
		ProjectRoot:  projectRoot,
		BeadID:       beadID,
		AttemptID:    attemptID,
		WorktreePath: wtPath,
		Registered:   true,
		CreatedAt:    time.Now().UTC(),
