	// bundle from wtPath to projectRoot so VerifyCleanWorktree can commit it.
	evidenceDir := filepath.ToSlash(filepath.Join(ExecuteBeadArtifactDir, attemptID))
	var evidenceCommittedInWt bool
	defer func() {
