		// (call RecoverOrphans before invoking workers).
		if err := gitOps.WorktreeAdd(projectRoot, wtPath, baseRev); err != nil {
			_ = os.RemoveAll(wtPath)
			return fmt.Errorf("creating isolated worktree: %w", err)
		}
		return nil
